  international: 7.5,
  express_domestic: 4.0,
  freight: 1.5,
};

export function calculateShipping(weight: number, destination: string): number {
  if (weight <= 0) {
    throw new ShippingError(
      `Invalid weight: ${weight}. Weight must be positive.`,
      "INVALID_WEIGHT"
    );
  }

  const rate = RATES[destination];

  if (rate === undefined) {
    throw new ShippingError(
      `Unknown destination: "${destination}".`,
      "UNKNOWN_DESTINATION"
    );
  }

  return weight * rate;
}

